async function* readLines(stream) {
  let buf = '';
  for await (const chunk of stream) {
    buf += chunk.toString();
    const lines = buf.split('\n');
    buf = lines.pop();
    for (const l of lines) yield l;
  }
  if (buf) yield buf;
}

